-- ============================================================
-- ACTUALIZACIÓN DE DÍAS Y PERSONAL — VACACIONES 2026
-- Fuente: col AL "TOTAL DIAS PENDIENTES" (217 colaboradores)
-- Acción: actualizar saldos por cédula/nombre + crear empleados faltantes.
-- Transaccional. Pega TODO y ejecuta (Run). Revisa el resumen final.
-- ============================================================
begin;

create temp table x(ced text, nn text, nombre text, dias numeric, cia text, proj text, pos text, ing date) on commit drop;

create or replace function pg_temp.nrm(t text) returns text language sql immutable as $func$
  select upper(regexp_replace(trim(translate(coalesce(t,''),
    'áéíóúÁÉÍÓÚñÑüÜ','aeiouAEIOUnNuU')), '\s+',' ','g'))
$func$;

-- 1) Actualizar días por cédula
update employees e set dias_pendientes = x.dias
  from x where x.ced <> '' and regexp_replace(coalesce(e.cedula,''),'\s','','g') = x.ced;

-- 2) Actualizar días por nombre (los que no cuadraron por cédula)
update employees e set dias_pendientes = x.dias
  from x where pg_temp.nrm(e.full_name) = x.nn
    and not exists (select 1 from x x2 where x2.ced<>'' and regexp_replace(coalesce(e.cedula,''),'\s','','g')=x2.ced);

-- 3) Crear empleados faltantes (no existen por cédula ni por nombre)
--    Se asignan a la empresa principal; company_id se resuelve por nombre si existe.
select gen_random_uuid(),
       (select id from companies order by created_at limit 1),
       'EXCEL-'||row_number() over (),
       x.nombre, nullif(x.ced,''), x.pos, null,
       coalesce(x.ing, current_date),
       x.dias, 'active', 'employee',
       lower(regexp_replace(translate(x.nombre,'áéíóúÁÉÍÓÚñÑ ','aeiouAEIOUnN.'),'[^a-z0-9.]','','g'))||'@lpdevelopment.com',
       lower(split_part(translate(x.nombre,'áéíóúÁÉÍÓÚñÑ','aeiouAEIOUnN'),' ',1))||'.'||lower(split_part(translate(x.nombre,'áéíóúÁÉÍÓÚñÑ','aeiouAEIOUnN'),' ',2))||'-'||substr(md5(x.nombre),1,4)
from x
where not exists (select 1 from employees e where x.ced<>'' and regexp_replace(coalesce(e.cedula,''),'\s','','g')=x.ced)
  and not exists (select 1 from employees e where pg_temp.nrm(e.full_name)=x.nn);

-- Resumen
select 'excel_total' k, count(*)::text v from x
union all select 'match_cedula', count(distinct e.id)::text from employees e join x on x.ced<>'' and regexp_replace(coalesce(e.cedula,''),'\s','','g')=x.ced
union all select 'match_nombre', count(distinct e.id)::text from employees e join x on pg_temp.nrm(e.full_name)=x.nn
union all select 'employees_total_post', count(*)::text from employees;

commit;
